section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/trunk-based-ci-gates.json",
  "type": "object",
  "required": [
    "pre_commit_lt_1s",
    "ci_lt_10min",
    "branch_protection_complete",
    "auto_revert_configured",
    "secret_scan_present"
  ],
  "properties": {
    "pre_commit_lt_1s": {
      "type": "boolean",
      "const": true
    },
    "ci_lt_10min": {
      "type": "boolean",
      "const": true
    },
    "branch_protection_complete": {
      "type": "boolean",
      "const": true
    },
    "required_status_jobs": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "minItems": 1
    },
    "auto_revert_configured": {
      "type": "boolean",
      "const": true
    },
    "secret_scan_present": {
      "type": "boolean",
      "const": true
    },
    "linear_history_required": {
      "type": "boolean"
    },
    "min_reviewers": {
      "type": "integer",
      "minimum": 1
    }
  },
  "additionalProperties": false
}
